// KST 03:00 → ET 전날 날짜 계산
const now = new Date();
const etOffset = 13;
const etDate = new Date(now.getTime() - etOffset * 60 * 60 * 1000);
const yesterday = new Date(etDate.getTime() - 24 * 60 * 60 * 1000);
const year  = yesterday.getUTCFullYear();
const month = String(yesterday.getUTCMonth() + 1).padStart(2, '0');
const day   = String(yesterday.getUTCDate()).padStart(2, '0');
const dateStr = `${year}-${month}-${day}`;
return [{ json: { query_date: dateStr } }];

// 누수 피처 드롭 + 정제
const LEAKAGE = new Set([
  'release_speed','release_spin_rate','release_extension',
  'release_pos_x','release_pos_y','release_pos_z','arm_angle',
  'pfx_x','pfx_z','plate_x','plate_z',
  'vx0','vy0','vz0','ax','ay','az',
  'effective_speed','api_break_z_with_gravity',
  'api_break_x_arm','api_break_x_batter_in',
  'spin_axis','spin_dir','hyper_speed',
  'spin_rate_deprecated','break_angle_deprecated','break_length_deprecated',
  'bat_speed','swing_length','attack_angle','attack_direction','swing_path_tilt',
  'intercept_ball_minus_batter_pos_x_inches','intercept_ball_minus_batter_pos_y_inches',
  'launch_speed','launch_angle','launch_speed_angle',
  'hit_distance_sc','hc_x','hc_y',
  'estimated_ba_using_speedangle','estimated_woba_using_speedangle','estimated_slg_using_speedangle',
  'delta_home_win_exp','delta_run_exp','delta_pitcher_run_exp',
  'post_away_score','post_home_score','post_bat_score','post_fld_score',
  'woba_value','woba_denom','babip_value','iso_value','zone','hit_location'
]);

const INT_COLS = new Set([
  'game_pk','at_bat_number','pitch_number','batter','pitcher','fielder_2',
  'balls','strikes','outs_when_up','inning','on_1b','on_2b','on_3b','game_year'
]);

const csvText = $input.first().json.data ?? '';
if (!csvText.trim()) {
  return [{ json: { error: 'CSV 없음', rows: 0, date: $('어제 ET 날짜 계산').first().json.query_date } }];
}

const lines = csvText.trim().split('\n');
const headers = lines[0].split(',').map(h => h.replace(/^"|"$/g, '').trim());
const results = [];
let invalidPKs = 0;

for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim()) continue;
  const values = lines[i].split(',').map(v => v.replace(/^"|"$/g, '').trim());
  const row = {};

  for (let j = 0; j < headers.length; j++) {
    const col = headers[j];
    if (LEAKAGE.has(col)) continue;
    let val = values[j] ?? null;
    if (val === '' || val === 'null' || val === 'NA' || val === 'NaN') val = null;
    if (val !== null) {
      if (INT_COLS.has(col)) {
        const p = parseInt(val, 10);
        val = isNaN(p) ? null : p;
      } else if (!isNaN(val)) {
        const p = parseFloat(val);
        val = isNaN(p) ? null : p;
      }
    }
    row[col] = val;
  }

  if (!row.game_pk || row.at_bat_number == null || !row.pitch_number) {
    invalidPKs++;
    continue;
  }
  results.push(row);
}

console.log(`정제 완료: ${results.length}행 | PK 실패: ${invalidPKs}건`);
return results.map(row => ({ json: row }));

// 예측 로그 vs 실제 투구 정확도 계산
const staticData = $getWorkflowStaticData('global');
const actualPitches = $input.all().map(i => i.json);
const predLog = staticData.prediction_log ?? [];

const today = $('어제 ET 날짜 계산').first().json.query_date;

if (predLog.length === 0 || actualPitches.length === 0) {
  return [{
    json: {
      date: today,
      total_predictions: predLog.length,
      correct_predictions: 0,
      accuracy: 0,
      accuracy_pct: 'N/A (예측 로그 또는 실제 데이터 없음)',
      drift_detected: false,
      drift_threshold: 0.40,
      pitch_type_stats: {}
    }
  }];
}

// 실제 투구 맵 생성: game_pk-at_bat_number-pitch_number → pitch_type
const actualMap = {};
for (const p of actualPitches) {
  const key = `${p.game_pk}-${p.at_bat_number}-${p.pitch_number}`;
  actualMap[key] = p.pitch_type;
}

// 예측 로그에서 실제 값 매칭
let correct = 0;
let total = 0;
const pitchStats = {};

for (const pred of predLog) {
  const key = `${pred.game_pk}-${pred.at_bat_number}-${pred.pitch_number}`;
  const actual = actualMap[key];
  if (!actual) continue;

  total++;
  const isCorrect = pred.predicted_pitch === actual;
  if (isCorrect) correct++;

  if (!pitchStats[actual]) pitchStats[actual] = { total: 0, correct: 0 };
  pitchStats[actual].total++;
  if (isCorrect) pitchStats[actual].correct++;

  // 실제 투구 업데이트
  pred.actual_pitch = actual;
  pred.correct = isCorrect;
}

const accuracy = total > 0 ? correct / total : 0;
const driftDetected = total >= 10 && accuracy < 0.40;

// 최저 성능 구종 찾기
let worstType = null;
let worstAcc = 1.0;
for (const [pt, s] of Object.entries(pitchStats)) {
  if (s.total >= 10) {
    const acc = s.correct / s.total;
    if (acc < worstAcc) { worstAcc = acc; worstType = pt; }
  }
}

console.log(`정확도: ${(accuracy*100).toFixed(1)}% (${correct}/${total})`);

return [{
  json: {
    date: today,
    total_predictions: total,
    correct_predictions: correct,
    accuracy: accuracy,
    accuracy_pct: `${(accuracy*100).toFixed(1)}%`,
    drift_detected: driftDetected,
    drift_threshold: 0.40,
    worst_pitch_type: worstType,
    worst_pitch_acc: worstAcc,
    pitch_type_stats: pitchStats
  }
}];

