// 성능 리포트 Static Data 저장
const staticData = $getWorkflowStaticData('global');
const accuracy = $('정확도 계산 및 드리프트 감지').item.json;
const aiRaw = $('성능 분석 AI').item.json.output ?? '{}';

let aiReport;
try { aiReport = JSON.parse(aiRaw); }
catch (e) { aiReport = { accuracy_summary: aiRaw, recommendation: '' }; }

if (!staticData.performance_log) staticData.performance_log = [];
staticData.performance_log.push({
  date: accuracy.date,
  accuracy: accuracy.accuracy,
  total: accuracy.total_predictions,
  drift: accuracy.drift_detected,
  ai_report: aiReport,
  ts: new Date().toISOString()
});

// 최근 30일치만 유지
if (staticData.performance_log.length > 30) {
  staticData.performance_log = staticData.performance_log.slice(-30);
}

// 오늘 prediction_log 초기화 (다음 경기 대비)
staticData.prediction_log = [];

console.log(`성능 리포트 저장: ${accuracy.date} / ${accuracy.accuracy_pct}`);

return [{
  json: {
    success: true,
    date: accuracy.date,
    accuracy: accuracy.accuracy_pct,
    drift: accuracy.drift_detected,
    ai_summary: aiReport.accuracy_summary
  }
}];
